use std::sync::{Arc, Mutex};
use std::thread;

struct Inventory {
    stock_level: i32,
}

impl Inventory {
    fn check_stock_level_shared(inventory: Arc<Mutex<Inventory>>) {
        let inventory = inventory.lock().unwrap();
        println!("Current stock level: {}", inventory.stock_level);
    }

    fn decrement_stock_shared(inventory: Arc<Mutex<Inventory>>) {
        let mut inventory = inventory.lock().unwrap();
        if inventory.stock_level > 0 {
            inventory.stock_level -= 1;
            println!("Stock decremented. New stock level: {}", inventory.stock_level);
        } else {
            println!("Stock level is already 0.");
        }
    }
}

fn main() {
    let inventory = Arc::new(Mutex::new(Inventory { stock_level: 10 }));

    let inventory_shared = Arc::clone(&inventory);
    let thread_1 = thread::spawn(move || {
        Inventory::check_stock_level_shared(inventory_shared);
    });

    let inventory_shared = Arc::clone(&inventory);
    let thread_2 = thread::spawn(move || {
        Inventory::decrement_stock_shared(inventory_shared);
    });

    thread_1.join().unwrap();
    thread_2.join().unwrap();
}